using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.name, Price = e.price, Quantity = e.qty }).ToList();

    #region CreateOrder — happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.50m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCustomerId()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _service.CreateOrder("cust-42", items);

        Assert.AreEqual("cust-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        var items = CreateItems(("A", 1m, 1), ("B", 2m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_WithVariousItems_CalculatesTotalCorrectly(
        string description, decimal price, int quantity, decimal expectedTotal)
    {
        var items = CreateItems(("Product", price, quantity));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total, $"Failed for: {description}");
    }

    public static IEnumerable<(string description, decimal price, int quantity, decimal expectedTotal)> TotalCalculationData =>
    [
        ("Single item, qty 1", 15.00m, 1, 15.00m),
        ("Single item, qty 5", 10.00m, 5, 50.00m),
        ("Zero price", 0.00m, 10, 0.00m),
        ("Zero quantity", 99.99m, 0, 0.00m),
        ("Fractional price", 3.33m, 3, 9.99m),
    ];

    [TestMethod]
    public void CreateOrder_MultipleCalls_AssignsUniqueIds()
    {
        var items = CreateItems(("Widget", 1m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder — validation

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.CustomerId, retrieved.CustomerId);
        Assert.AreEqual(created.Total, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_AfterMultipleCreates_ReturnsCorrectOrder()
    {
        var order1 = _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        var order2 = _service.CreateOrder("cust-2", CreateItems(("B", 2m, 2)));

        var retrieved = _service.GetOrder(order2.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual("cust-2", retrieved.CustomerId);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllTheirOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-999");

        Assert.IsNotEmpty(orders is not null ? [] : []);
        Assert.IsNotNull(orders);
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyOrdersForSpecifiedCustomer()
    {
        var c1Order = _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-1");

        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual(c1Order.Id, single.Id);
    }

    #endregion
}

